{"file_text": "<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center"
         style="cursor: pointer;" @onclick="ToggleExpanded">
        <h6 class="mb-0">Change Password</h6>
        <span>@(IsExpanded ? "▲" : "▼")</span>
    </div>
    @if (IsExpanded)
    {
        <div class="card-body">
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="CurrentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="NewPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="ConfirmPassword" />
            </div>

            @if (!string.IsNullOrEmpty(_errorMessage))
            {
                <div class="alert alert-danger py-2">@_errorMessage</div>
            }
            @if (_success)
            {
                <div class="alert alert-success py-2">Password updated successfully.</div>
            }

            <button class="btn btn-primary" @onclick="Submit" disabled="@_saving">
                @(_saving ? "Updating…" : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string current, string newPwd)> OnChangePassword { get; set; }

    private bool IsExpanded;
    private string CurrentPassword = "";
    private string NewPassword = "";
    private string ConfirmPassword = "";
    private string? _errorMessage;
    private bool _success;
    private bool _saving;

    private void ToggleExpanded() => IsExpanded = !IsExpanded;

    private async Task Submit()
    {
        _errorMessage = null;
        _success = false;

        if (string.IsNullOrWhiteSpace(CurrentPassword) ||
            string.IsNullOrWhiteSpace(NewPassword))
        {
            _errorMessage = "All fields are required.";
            return;
        }

        if (NewPassword != ConfirmPassword)
        {
            _errorMessage = "New passwords do not match.";
            return;
        }

        if (NewPassword.Length < 8)
        {
            _errorMessage = "Password must be at least 8 characters.";
            return;
        }

        _saving = true;
        try
        {
            await OnChangePassword.InvokeAsync((CurrentPassword, NewPassword));
            _success = true;
            CurrentPassword = "";
            NewPassword = "";
            ConfirmPassword = "";
        }
        catch (Exception ex)
        {
            _errorMessage = ex.Message;
        }
        finally
        {
            _saving = false;
        }
    }
}
