@* Sidebar navigation with vertical tabs *@

<nav class="settings-sidebar">
    @foreach (var section in Sections)
    {
        <button class="settings-sidebar-item @(section == ActiveSection ? "active" : "")"
                @onclick="() => SelectSection(section)">
            <span class="settings-sidebar-icon">@GetIcon(section)</span>
            <span>@section</span>
        </button>
    }
</nav>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private async Task SelectSection(string section) =>
        await OnSectionChanged.InvokeAsync(section);

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

