@using sv_1082dc7e6f37441695f07ea230f2281d.Services
@inject ISettingsService SettingsService

<h4 class="mb-4">Profile</h4>

@if (_loading)
{
    <p class="text-muted">Loading profile…</p>
}
else if (_profile is not null)
{
    @if (_statusMessage is not null)
    {
        <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show py-2">
            @_statusMessage
            <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-8">
            <div class="mb-3">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="_displayName" />
            </div>
            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="_email" />
            </div>
            <div class="mb-3">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="4" @bind="_bio"></textarea>
            </div>
        </div>
        <div class="col-md-4 text-center">
            <div class="mb-2">
                <img src="@_profile.AvatarUrl" alt="Avatar" class="rounded-circle"
                     style="width: 120px; height: 120px; object-fit: cover; border: 3px solid #dee2e6;" />
            </div>
            <small class="text-muted text-break">@_profile.AvatarUrl</small>
        </div>
    </div>

    <div class="d-flex gap-2 mt-3">
        <button class="btn btn-primary" @onclick="SaveChanges" disabled="@_saving">
            @(_saving ? "Saving…" : "Save Changes")
        </button>
        <button class="btn btn-outline-secondary" @onclick="DiscardChanges">
            Discard Changes
        </button>
    </div>
}

@code {
    private UserProfile? _profile;
    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private bool _loading = true;
    private bool _saving;
    private string? _statusMessage;
    private bool _isError;

    protected override async Task OnInitializedAsync()
    {
        await LoadProfile();
        _loading = false;
    }

    private async Task LoadProfile()
    {
        _profile = await SettingsService.GetProfileAsync();
        ResetFields();
    }

    private void ResetFields()
    {
        if (_profile is null) return;
        _displayName = _profile.DisplayName;
        _email = _profile.Email;
        _bio = _profile.Bio;
    }

    private async Task SaveChanges()
    {
        _saving = true;
        _statusMessage = null;
        try
        {
            var updated = _profile! with
            {
                DisplayName = _displayName,
                Email = _email,
                Bio = _bio
            };
            await SettingsService.SaveProfileAsync(updated);
            _profile = updated;
            _statusMessage = "Profile saved successfully!";
            _isError = false;
        }
        catch (Exception ex)
        {
            _statusMessage = $"Failed to save: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private void DiscardChanges()
    {
        ResetFields();
        _statusMessage = null;
    }
}

@using sv_1082dc7e6f37441695f07ea230f2281d.Services
@inject ISettingsService SettingsService

<h4 class="mb-4">Notifications</h4>

@if (_loading)
{
    <p class="text-muted">Loading preferences…</p>
}
else
{
    @if (_statusMessage is not null)
    {
        <div class="alert alert-success alert-dismissible fade show py-2">
            @_statusMessage
            <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
        </div>
    }

    <div class="card mb-3">
        <div class="card-body">
            <h6 class="card-title mb-3">Notification Channels</h6>

            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="emailNotif"
                       checked="@_emailNotifications"
                       @onchange="e => _emailNotifications = (bool)(e.Value ?? false)" />
                <label class="form-check-label" for="emailNotif">Email Notifications</label>
            </div>

            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="pushNotif"
                       checked="@_pushNotifications"
                       @onchange="e => _pushNotifications = (bool)(e.Value ?? false)" />
                <label class="form-check-label" for="pushNotif">Push Notifications</label>
            </div>

            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="weeklyDigest"
                       checked="@_weeklyDigest"
                       @onchange="e => _weeklyDigest = (bool)(e.Value ?? false)" />
                <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
            </div>
        </div>
    </div>

    <div class="card mb-3">
        <div class="card-body">
            <h6 class="card-title mb-3">Muted Channels</h6>
            @foreach (var channel in _allChannels)
            {
                <div class="form-check mb-2">
                    <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                           checked="@_mutedChannels.Contains(channel)"
                           @onchange="e => ToggleMutedChannel(channel, (bool)(e.Value ?? false))" />
                    <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
                </div>
            }
        </div>
    </div>

    <button class="btn btn-primary" @onclick="SavePreferences" disabled="@_saving">
        @(_saving ? "Saving…" : "Save Preferences")
    </button>
}

@code {
    private bool _loading = true;
    private bool _saving;
    private string? _statusMessage;

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = [];

    private static readonly string[] _allChannels = ["general", "announcements", "marketing", "engineering", "support"];

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _mutedChannels = [.. prefs.MutedChannels];
        _loading = false;
    }

    private void ToggleMutedChannel(string channel, bool isMuted)
    {
        if (isMuted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SavePreferences()
    {
        _saving = true;
        _statusMessage = null;
        try
        {
            var prefs = new NotificationPrefs(
                _emailNotifications, _pushNotifications, _weeklyDigest,
                _mutedChannels.ToList());
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            _statusMessage = "Notification preferences saved!";
        }
        finally
        {
            _saving = false;
        }
    }
}

@using sv_1082dc7e6f37441695f07ea230f2281d.Services
@inject ISettingsService SettingsService

<h4 class="mb-4">Security</h4>

@if (_loading)
{
    <p class="text-muted">Loading security settings…</p>
}
else
{
    @if (_statusMessage is not null)
    {
        <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show py-2">
            @_statusMessage
            <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
        </div>
    }

    <ChangePasswordPanel OnChangePassword="HandleChangePassword" />

    <div class="card mb-3">
        <div class="card-body d-flex justify-content-between align-items-center">
            <div>
                <h6 class="mb-1">Two-Factor Authentication</h6>
                <small class="text-muted">
                    @if (_twoFactorEnabled)
                    {
                        <span class="badge bg-success me-1">Enabled</span>
                        <span>Your account is protected with 2FA.</span>
                    }
                    else
                    {
                        <span class="badge bg-warning text-dark me-1">Disabled</span>
                        <span>Enable 2FA for extra security.</span>
                    }
                </small>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="twoFactor"
                       checked="@_twoFactorEnabled"
                       @onchange="e => _twoFactorEnabled = (bool)(e.Value ?? false)" />
            </div>
        </div>
    </div>

    @if (_lastPasswordChange.HasValue)
    {
        <p class="text-muted small mb-3">
            Last password change: @_lastPasswordChange.Value.ToString("MMMM d, yyyy")
        </p>
    }

    <h5 class="mb-3">Active Sessions</h5>
    <ActiveSessionsTable Sessions="_sessions"
                         OnRevokeRequested="ShowRevokeDialog" />

    <RevokeSessionDialog Visible="_showRevokeDialog"
                         Session="_sessionToRevoke"
                         OnConfirm="ConfirmRevoke"
                         OnCancel="CancelRevoke" />
}

@code {
    private bool _loading = true;
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = [];
    private string? _statusMessage;
    private bool _isError;

    private bool _showRevokeDialog;
    private ActiveSession? _sessionToRevoke;

    protected override async Task OnInitializedAsync()
    {
        await LoadSettings();
        _loading = false;
    }

    private async Task LoadSettings()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = settings.Sessions;
    }

    private async Task HandleChangePassword((string current, string newPwd) args)
    {
        await SettingsService.ChangePasswordAsync(args.current, args.newPwd);
        _lastPasswordChange = DateTime.UtcNow;
        _statusMessage = "Password changed successfully!";
        _isError = false;
    }

    private void ShowRevokeDialog(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeDialog = true;
    }

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is null) return;
        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _sessions = _sessions.Where(s => s.Id != _sessionToRevoke.Id).ToList();
        _statusMessage = $"Session on {_sessionToRevoke.Device} revoked.";
        _isError = false;
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }

    private void CancelRevoke()
    {
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }
}

@using sv_1082dc7e6f37441695f07ea230f2281d.Services
@inject ISettingsService SettingsService

<h4 class="mb-4">Appearance</h4>

@if (_loading)
{
    <p class="text-muted">Loading appearance settings…</p>
}
else
{
    @if (_statusMessage is not null)
    {
        <div class="alert alert-success alert-dismissible fade show py-2">
            @_statusMessage
            <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-6">
            <div class="card mb-3">
                <div class="card-body">
                    <h6 class="card-title mb-3">Theme</h6>
                    @foreach (var theme in _themes)
                    {
                        <div class="form-check mb-2">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")" value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-3">
                <div class="card-body">
                    <h6 class="card-title mb-3">Font Size</h6>
