{"file_text": "@using sv_1082dc7e6f37441695f07ea230f2281d.Services
@inject ISettingsService SettingsService

<h4 class="mb-4">Security</h4>

@if (_loading)
{
    <p class="text-muted">Loading security settings…</p>
}
else
{
    @if (_statusMessage is not null)
    {
        <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show py-2">
            @_statusMessage
            <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
        </div>
    }

    <ChangePasswordPanel OnChangePassword="HandleChangePassword" />

    <div class="card mb-3">
        <div class="card-body d-flex justify-content-between align-items-center">
            <div>
                <h6 class="mb-1">Two-Factor Authentication</h6>
                <small class="text-muted">
                    @if (_twoFactorEnabled)
                    {
                        <span class="badge bg-success me-1">Enabled</span>
                        <span>Your account is protected with 2FA.</span>
                    }
                    else
                    {
                        <span class="badge bg-warning text-dark me-1">Disabled</span>
                        <span>Enable 2FA for extra security.</span>
                    }
                </small>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="twoFactor"
                       checked="@_twoFactorEnabled"
                       @onchange="e => _twoFactorEnabled = (bool)(e.Value ?? false)" />
            </div>
        </div>
    </div>

    @if (_lastPasswordChange.HasValue)
    {
        <p class="text-muted small mb-3">
            Last password change: @_lastPasswordChange.Value.ToString("MMMM d, yyyy")
        </p>
    }

    <h5 class="mb-3">Active Sessions</h5>
    <ActiveSessionsTable Sessions="_sessions"
                         OnRevokeRequested="ShowRevokeDialog" />

    <RevokeSessionDialog Visible="_showRevokeDialog"
                         Session="_sessionToRevoke"
                         OnConfirm="ConfirmRevoke"
                         OnCancel="CancelRevoke" />
}

@code {
    private bool _loading = true;
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = [];
    private string? _statusMessage;
    private bool _isError;

    private bool _showRevokeDialog;
    private ActiveSession? _sessionToRevoke;

    protected override async Task OnInitializedAsync()
    {
        await LoadSettings();
        _loading = false;
    }

    private async Task LoadSettings()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = settings.Sessions;
    }

    private async Task HandleChangePassword((string current, string newPwd) args)
    {
        await SettingsService.ChangePasswordAsync(args.current, args.newPwd);
        _lastPasswordChange = DateTime.UtcNow;
        _statusMessage = "Password changed successfully!";
        _isError = false;
    }

    private void ShowRevokeDialog(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeDialog = true;
    }

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is null) return;
        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _sessions = _sessions.Where(s => s.Id != _sessionToRevoke.Id).ToList();
        _statusMessage = $"Session on {_sessionToRevoke.Device} revoked.";
        _isError = false;
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }

    private void CancelRevoke()
    {
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }
}
", "path": "/tmp/sv-1082dc7e6f37441695f07ea230f2281d/Components/Pages/Settings/SecuritySettings.razor"}

{"file_text": "@using sv_1082dc7e6f37441695f07ea230f2281d.Services
@inject ISettingsService SettingsService

<h4 class="mb-4">Appearance</h4>

@if (_loading)
{
    <p class="text-muted">Loading appearance settings…</p>
}
else
{
    @if (_statusMessage is not null)
    {
        <div class="alert alert-success alert-dismissible fade show py-2">
            @_statusMessage
            <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-6">
            <div class="card mb-3">
                <div class="card-body">
                    <h6 class="card-title mb-3">Theme</h6>
                    @foreach (var theme in _themes)
                    {
                        <div class="form-check mb-2">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")" value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-3">
                <div class="card-body">
                    <h6 class="card-title mb-3">Font Size</h6>
                    @foreach (var size in _fontSizes)
                    {
                        <div class="form-check form-check-inline">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"fs-{size}")" value="@size"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-3">
                <div class="card-body">
                    <h6 class="card-title mb-3">Language</h6>
                    <select class="form-select" @bind="_language">
                        @foreach (var lang in _languages)
                        {
                            <option value="@lang">@lang</option>
                        }
                    </select>
                </div>
            </div>

            <div class="card mb-3">
                <div class="card-body d-flex justify-content-between align-items-center">
                    <h6 class="mb-0">Compact Mode</h6>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode"
                               checked="@_compactMode"
                               @onchange="e => _compactMode = (bool)(e.Value ?? false)" />
                    </div>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@_saving">
                @(_saving ? "Saving…" : "Save")
            </button>
        </div>

        <div class="col-md-6">
            <h6 class="mb-3">Live Preview</h6>
            <div class="border rounded p-3" style="@PreviewStyles()">
                <h5 style="@PreviewFontStyle()">Dashboard</h5>
                <p style="@PreviewFontStyle()" class="@(_compactMode ? "mb-1" : "mb-3")">
                    Welcome back! Here's your daily summary.
                </p>
                <div class="d-flex gap-2 @(_compactMode ? "mb-1" : "mb-3")">
                    <span class="badge" style="@PreviewBadgeStyle()">12 Tasks</span>
                    <span class="badge" style="@PreviewBadgeStyle()">3 Messages</span>
                </div>
                <div class="@(_compactMode ? "p-1" : "p-2") border rounded" style="@PreviewCardStyle()">
                    <small style="@PreviewFontStyle()">Sample card content with @_theme theme, @_fontSize font, @_language language.</small>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private bool _loading = true;
    private bool _saving;
    private string? _statusMessage;

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private async Task SaveAppearance()
    {
        _saving = true;
        _statusMessage = null;
        try
        {
            await SettingsService.SaveAppearanceAsync(
                new AppearanceSettings(_theme, _fontSize, _language, _compactMode));
            _statusMessage = "Appearance settings saved!";
        }
        finally
        {
            _saving = false;
        }
    }

    private string PreviewStyles()
    {
        var bg = _theme == "Dark" ? "#1e1e1e" : "#ffffff";
        var color = _theme == "Dark" ? "#e0e0e0" : "#212529";
        return $"background-color: {bg}; color: {color}; min-height: 200px; transition: all 0.3s ease;";
    }

    private string PreviewFontStyle()
    {
        var size = _fontSize switch
        {
            "Small" => "0.85rem",
            "Large" => "1.15rem",
            _ => "1rem"
        };
        return $"font-size: {size};";
    }

    private string PreviewBadgeStyle()
    {
        var bg = _theme == "Dark" ? "#4a9eff" : "#0d6efd";
        return $"background-color: {bg};";
    }

    private string PreviewCardStyle()
    {
        var bg = _theme == "Dark" ? "#2d2d2d" : "#f8f9fa";
        var border = _theme == "Dark" ? "#444" : "#dee2e6";
        return $"background-color: {bg}; border-color: {border} !important;";
    }
}
