@using sv_1082dc7e6f37441695f07ea230f2281d.Services
@inject ISettingsService SettingsService

<h4 class="mb-4">Security</h4>

@if (_loading)
{
    <p class="text-muted">Loading security settings…</p>
}
else
{
    @if (_statusMessage is not null)
    {
        <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show py-2">
            @_statusMessage
            <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
        </div>
    }

    <ChangePasswordPanel OnChangePassword="HandleChangePassword" />

    <div class="card mb-3">
        <div class="card-body d-flex justify-content-between align-items-center">
            <div>
                <h6 class="mb-1">Two-Factor Authentication</h6>
                <small class="text-muted">
                    @if (_twoFactorEnabled)
                    {
                        <span class="badge bg-success me-1">Enabled</span>
                        <span>Your account is protected with 2FA.</span>
                    }
                    else
                    {
                        <span class="badge bg-warning text-dark me-1">Disabled</span>
                        <span>Enable 2FA for extra security.</span>
                    }
                </small>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="twoFactor"
                       checked="@_twoFactorEnabled"
                       @onchange="e => _twoFactorEnabled = (bool)(e.Value ?? false)" />
            </div>
        </div>
    </div>

    @if (_lastPasswordChange.HasValue)
    {
        <p class="text-muted small mb-3">
            Last password change: @_lastPasswordChange.Value.ToString("MMMM d, yyyy")
        </p>
    }

    <h5 class="mb-3">Active Sessions</h5>
    <ActiveSessionsTable Sessions="_sessions"
                         OnRevokeRequested="ShowRevokeDialog" />

    <RevokeSessionDialog Visible="_showRevokeDialog"
                         Session="_sessionToRevoke"
                         OnConfirm="ConfirmRevoke"
                         OnCancel="CancelRevoke" />
}

@code {
    private bool _loading = true;
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = [];
    private string? _statusMessage;
    private bool _isError;

    private bool _showRevokeDialog;
    private ActiveSession? _sessionToRevoke;

    protected override async Task OnInitializedAsync()
    {
        await LoadSettings();
        _loading = false;
    }

    private async Task LoadSettings()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = settings.Sessions;
    }

    private async Task HandleChangePassword((string current, string newPwd) args)
    {
        await SettingsService.ChangePasswordAsync(args.current, args.newPwd);
        _lastPasswordChange = DateTime.UtcNow;
        _statusMessage = "Password changed successfully!";
        _isError = false;
    }

    private void ShowRevokeDialog(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeDialog = true;
    }

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is null) return;
        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _sessions = _sessions.Where(s => s.Id != _sessionToRevoke.Id).ToList();
        _statusMessage = $"Session on {_sessionToRevoke.Device} revoked.";
        _isError = false;
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }

    private void CancelRevoke()
    {
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }
}

