                     OnSectionChanged="section => _activeSection = section" />

    <div class="settings-content">
        @switch (_activeSection)
        {
            case "Profile":
                <ProfileSettings />
                break;
            case "Notifications":
                <NotificationSettings />
                break;
            case "Security":
                <SecuritySettings />
                break;
            case "Appearance":
                <AppearanceSettings />
                break;
