toolArgs.file_text:
@page "/settings"
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <SettingsSidebar ActiveSection="@_activeSection"
                     OnSectionChanged="section => _activeSection = section" />

    <div class="settings-content">
        @switch (_activeSection)
        {
            case "Profile":
                <ProfileSettings />
                break;
            case "Notifications":
                <NotificationSettings />
                break;
            case "Security":
                <SecuritySettings />
                break;
            case "Appearance":
                <AppearanceSettings />
                break;
        }
    </div>
</div>

@code {
    private string _activeSection = "Profile";
}

.settings-sidebar {
    display: flex;
    flex-direction: column;
    width: 220px;
    background-color: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1rem 0;
}

.settings-sidebar-item {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.75rem 1.25rem;
    border: none;
    background: none;
    text-align: left;
    font-size: 0.95rem;
    color: #495057;
    cursor: pointer;
    transition: background-color 0.15s, color 0.15s;
}

.settings-sidebar-item:hover {
    background-color: #e9ecef;
    color: #212529;
}

.settings-sidebar-item.active {
    background-color: #0d6efd;
    color: #fff;
    font-weight: 500;
}

.settings-sidebar-icon {
    font-size: 1.1rem;
    width: 1.5rem;
    text-align: center;
}

